#include <cstdlib>

void
print_token();

namespace lex {

static const char* kTokenNames[] = {
  "identifier",       // IDENTIFIER
  "numeric_constant", // CONSTANT
  "string_literal",   // STRING_LITERAL
  "int",              // INT
  "return",           // RETURN
  "if",               // IF
  "else",             // ELSE
  "while",            // WHILE
  "break",            // BREAK
  "continue",         // CONTINUE
  "void",             // VOID
  "const",            // CONST
  "l_brace",          // L_BRACE
  "r_brace",          // R_BRACE
  "l_square",         // L_SQUARE
  "r_square",         // R_SQUARE
  "l_paren",          // L_PAREN
  "r_paren",          // R_PAREN
  "semi",             // SEMI
  "comma",            // COMMA
  "equal",            // EQUAL
  "equalequal",       // EQUALEQUAL
  "plus",             // PLUS
  "minus",            // MINUS
  "star",             // STAR
  "slash",            // SLASH
  "percent",          // PERCENT
  "exclaim",          // EXCLAIM
  "exclaimequal",     // EXCLAIMEQUAL
  "ampamp",           // AMPAMP
  "pipepipe",         // PIPEPIPE
  "less",             // LESS
  "greater",          // GREATER
  "lessequal",        // LESSEQUAL
  "greaterequal",     // GREATEREQUAL
  "amp",              // AMP
  "pipe",             // PIPE
  "caret",            // CARET
  "tilde",            // TILDE
  "lshift",           // LSHIFT
  "rshift",           // RSHIFT
  "plusequal",        // PLUSEQUAL
  "minusequal",       // MINUSEQUAL
  "starequal",        // STAREQUAL
  "slashequal",       // SLASHEQUAL
  "percentequal",     // PERCENTEQUAL
  "ampequal",         // AMPEQUAL
  "pipeequal",        // PIPEEQUAL
  "caretequal",       // CARETEQUAL
  "lshiftequal",      // LSHIFTEQUAL
  "rshiftequal",      // RSHIFTEQUAL
  "plusplus",         // PLUSPLUS
  "minusminus",       // MINUSMINUS
  "arrow",            // ARROW
  "question",         // QUESTION
  "colon",            // COLON
  "dot",              // DOT
  "ellipsis",         // ELLIPSIS
};

const char*
id2str(Id id)
{
  static char sCharBuf[2] = { 0, 0 };
  if (id == Id::YYEOF) {
    return "eof";
  }
  else if (id < Id::IDENTIFIER) {
    sCharBuf[0] = char(id);
    return sCharBuf;
  }
  return kTokenNames[int(id) - int(Id::IDENTIFIER)];
}

G g;

int
come(int tokenId, const char* yytext, int yyleng)
{
  g.mId = Id(tokenId);
  g.mText = { yytext, std::size_t(yyleng) };

  // Save the starting column as the token's column
  g.mTokenColumn = g.mColumn;

  // For eof token: don't set StartOfLine
  // If StartOfLine is true at eof, it means a newline was just processed,
  // but eof should be at the end of the previous line
  if (tokenId == Id::YYEOF) {
    g.mStartOfLine = false;
  }

  print_token();

  // Advance column past the token
  g.mColumn += yyleng;

  g.mStartOfLine = false;
  g.mLeadingSpace = false;

  return tokenId;
}

void
handle_line_marker(const char* yytext, int yyleng)
