   265	    dynamic_cast<antlr4::tree::TerminalNode*>(ctx->unaryOperator()->children[0])
   266	      ->getSymbol()
   267	      ->getType()) {
   268	    case ast::Plus:
   269	      ret->op = ret->kPos;
   270	      break;
   271	
   272	    case ast::Minus:
   273	      ret->op = ret->kNeg;
   274	      break;
   275	
   276	    default:
   277	      ABORT();
   278	  }
   279	
   280	  ret->sub = self(ctx->unaryExpression());
   281	
   282	  return ret;
   283	}
