FunctionDecl*
Ast2Asg::operator()(ast::FunctionDefinitionContext* ctx)
{
  auto ret = make<FunctionDecl>();
  mCurrentFunc = ret;

  auto type = make<Type>();
  ret->type = type;

  auto sq = self(ctx->declarationSpecifiers());
  type->spec = sq.first, type->qual = sq.second;

  auto [texp, name] = self(ctx->directDeclarator(), nullptr);
  auto funcType = texp->dcst<FunctionType>();
  type->texp = funcType;
  ret->name = std::move(name);

  Symtbl localDecls(self);

  // 函数定义在签名之后就加入符号表，以允许递归调用
  (*mSymtbl)[ret->name] = ret;

  // Add parameters to function and symbol table
  if (funcType) {
    for (auto p : funcType->params) {
      auto paramDecl = make<VarDecl>();
      paramDecl->type = p;
      // Extract parameter name from the parameterTypeList context
      ret->params.push_back(paramDecl);
      // We need to get the parameter names from the AST context
    }
  }

  // Extract parameter names from the AST
  auto directDeclCtx = ctx->directDeclarator();
  // Walk through the directDeclarator chain to find the parameterTypeList
  while (directDeclCtx->directDeclarator()) {
    if (directDeclCtx->parameterTypeList()) {
      for (auto&& param : directDeclCtx->parameterTypeList()->parameterList()->parameterDeclaration()) {
        auto [ptexp, pname] = self(param->declarator(), nullptr);
        // Find matching paramDecl and set name
        for (auto& pd : ret->params) {
          if (pd->name.empty()) {
            pd->name = pname;
            pd->type->texp = ptexp;
            (*mSymtbl)[pname] = pd;
            break;
          }
        }
      }
      break;
    }
    directDeclCtx = directDeclCtx->directDeclarator();
  }

  ret->body = self(ctx->compoundStatement());

  return ret;
}

