Expr*
Ast2Asg::operator()(ast::PostfixExpressionContext* ctx)
{
  auto children = ctx->children;

  if (children.size() == 1) {
    return self(dynamic_cast<ast::PrimaryExpressionContext*>(children[0]));
  }

  // Function call: postfixExpression LeftParen ... RightParen
  if (ctx->LeftParen()) {
    auto sub = self(dynamic_cast<ast::PostfixExpressionContext*>(children[0]));
    auto ret = make<CallExpr>();
    ret->head = sub;

    // Parse arguments
    auto assignExprs = ctx->assignmentExpression();
    for (auto&& arg : assignExprs) {
      ret->args.push_back(self(arg));
    }

    return ret;
  }

  // Array subscript: postfixExpression LeftBracket expression RightBracket
  if (ctx->LeftBracket()) {
    auto sub = self(dynamic_cast<ast::PostfixExpressionContext*>(children[0]));
    auto idx = self(ctx->expression());
    auto ret = make<BinaryExpr>();
    ret->op = ret->kIndex;
    ret->lft = sub;
    ret->rht = idx;
    return ret;
  }

  ABORT();
}

