  if (auto p = obj->dcst<CallExpr>())
    return self(p);
  if (auto p = obj->dcst<ParenExpr>())
    return self(p);
  if (auto p = obj->dcst<ImplicitCastExpr>())
    return self(p);
  if (auto p = obj->dcst<InitListExpr>())
    return self(p);
  if (auto p = obj->dcst<ArraySubscriptExpr>())
    return self(p);
  ABORT();
}

llvm::Constant*
EmitIR::operator()(IntegerLiteral* obj)
{
  return llvm::ConstantInt::get(self(obj->type), obj->val);
}

llvm::Value*
EmitIR::operator()(DeclRefExpr* obj)
{
  auto decl = obj->decl;
  if (auto gv = llvm::dyn_cast<llvm::GlobalVariable>(decl->any))
    return gv;
  if (auto func = llvm::dyn_cast<llvm::Function>(decl->any))
    return func;
  if (auto alloca = llvm::dyn_cast<llvm::AllocaInst>(decl->any))
    return alloca;
  ABORT();
}

llvm::Value*
EmitIR::operator()(BinaryExpr* obj)
{
  auto& irb = *mCurIrb;

  // Assignment
  if (obj->op == BinaryExpr::kAssign) {
    auto lhs = self(obj->lft);
    auto rhs = self(obj->rht);
    if (auto alloca = llvm::dyn_cast<llvm::AllocaInst>(lhs))
      irb.CreateStore(rhs, alloca);
    else if (auto gv = llvm::dyn_cast<llvm::GlobalVariable>(lhs))
      irb.CreateStore(rhs, gv);
    else
      ABORT();
    return rhs;
  }

  // Comma
  if (obj->op == BinaryExpr::kComma) {
    self(obj->lft);
    return self(obj->rht);
  }

  // Index (array subscript)
  if (obj->op == BinaryExpr::kIndex) {
    auto arr = self(obj->lft);
    auto idx = self(obj->rht);
    llvm::Value* elemPtr;
    if (auto alloca = llvm::dyn_cast<llvm::AllocaInst>(arr)) {
      elemPtr = irb.CreateInBoundsGEP(alloca->getAllocatedType(), alloca, {llvm::ConstantInt::get(llvm::Type::getInt32Ty(mCtx), 0), idx});
    } else if (auto gv = llvm::dyn_cast<llvm::GlobalVariable>(arr)) {
      elemPtr = irb.CreateInBoundsGEP(gv->getValueType(), gv, {llvm::ConstantInt::get(llvm::Type::getInt32Ty(mCtx), 0), idx});
    } else {
      // Pointer type - treat as pointer arithmetic
      elemPtr = irb.CreateInBoundsGEP(mIntTy, arr, idx);
    }
    return irb.CreateLoad(mIntTy, elemPtr);
  }

  auto lhs = self(obj->lft);
  auto rhs = self(obj->rht);

  switch (obj->op) {
    case BinaryExpr::kAdd:
      return irb.CreateAdd(lhs, rhs);
    case BinaryExpr::kSub:
      return irb.CreateSub(lhs, rhs);
    case BinaryExpr::kMul:
      return irb.CreateMul(lhs, rhs);
    case BinaryExpr::kDiv:
      return irb.CreateSDiv(lhs, rhs);
    case BinaryExpr::kMod:
      return irb.CreateSRem(lhs, rhs);
    case BinaryExpr::kGt:
      return irb.CreateICmpSGT(lhs, rhs);
    case BinaryExpr::kLt:
      return irb.CreateICmpSLT(lhs, rhs);
    case BinaryExpr::kGe:
      return irb.CreateICmpSGE(lhs, rhs);
    case BinaryExpr::kLe:
      return irb.CreateICmpSLE(lhs, rhs);
    case BinaryExpr::kEq:
      return irb.CreateICmpEQ(lhs, rhs);
    case BinaryExpr::kNe:
      return irb.CreateICmpNE(lhs, rhs);
    case BinaryExpr::kAnd: {
      // Short-circuit: lhs && rhs
      auto lhsBb = irb.GetInsertBlock();
      auto rhsBb = llvm::BasicBlock::Create(mCtx, "and.rhs", mCurFunc);
      auto mergeBb = llvm::BasicBlock::Create(mCtx, "and.merge", mCurFunc);
      auto lhsBool = irb.CreateICmpNE(lhs, llvm::ConstantInt::get(lhs->getType(), 0));
      irb.CreateCondBr(lhsBool, rhsBb, mergeBb);
      irb.SetInsertPoint(rhsBb);
      auto rhsVal = self(obj->rht);
      auto rhsBool = irb.CreateICmpNE(rhsVal, llvm::ConstantInt::get(rhsVal->getType(), 0));
      auto rhsResult = irb.CreateZExt(rhsBool, mIntTy);
      irb.CreateBr(mergeBb);
      irb.SetInsertPoint(mergeBb);
      auto phi = irb.CreatePHI(mIntTy, 2);
      phi->addIncoming(llvm::ConstantInt::get(mIntTy, 0), lhsBb);
      phi->addIncoming(rhsResult, rhsBb);
      return phi;
    }
    case BinaryExpr::kOr: {
      // Short-circuit: lhs || rhs
      auto lhsBb = irb.GetInsertBlock();
      auto rhsBb = llvm::BasicBlock::Create(mCtx, "or.rhs", mCurFunc);
      auto mergeBb = llvm::BasicBlock::Create(mCtx, "or.merge", mCurFunc);
      auto lhsBool = irb.CreateICmpNE(lhs, llvm::ConstantInt::get(lhs->getType(), 0));
      irb.CreateCondBr(lhsBool, mergeBb, rhsBb);
      irb.SetInsertPoint(rhsBb);
      auto rhsVal = self(obj->rht);
      auto rhsBool = irb.CreateICmpNE(rhsVal, llvm::ConstantInt::get(rhsVal->getType(), 0));
      auto rhsResult = irb.CreateZExt(rhsBool, mIntTy);
      irb.CreateBr(mergeBb);
      irb.SetInsertPoint(mergeBb);
      auto phi = irb.CreatePHI(mIntTy, 2);
      phi->addIncoming(llvm::ConstantInt::get(mIntTy, 1), lhsBb);
      phi->addIncoming(rhsResult, rhsBb);
      return phi;
    }
    default:
      ABORT();
  }
}

llvm::Value*
EmitIR::operator()(UnaryExpr* obj)
{
  auto& irb = *mCurIrb;
  auto sub = self(obj->sub);
  switch (obj->op) {
    case UnaryExpr::kPos:
      return sub;
    case UnaryExpr::kNeg:
      return irb.CreateNeg(sub);
    case UnaryExpr::kNot:
      return irb.CreateXor(sub, llvm::ConstantInt::get(sub->getType(), 1));
    default:
      ABORT();
  }
}

llvm::Value*
EmitIR::operator()(CallExpr* obj)
{
  auto& irb = *mCurIrb;
  auto callee = self(obj->head);
  auto func = llvm::dyn_cast<llvm::Function>(callee);
  if (!func)
    ABORT();

  std::vector<llvm::Value*> args;
  for (auto&& arg : obj->args)
    args.push_back(self(arg));
  return irb.CreateCall(func, args);
}

llvm::Value*
EmitIR::operator()(ParenExpr* obj)
{
  return self(obj->sub);
}

llvm::Value*
EmitIR::operator()(ImplicitCastExpr* obj)
{
  auto sub = self(obj->sub);
  auto& irb = *mCurIrb;
  switch (obj->kind) {
    case ImplicitCastExpr::kLValueToRValue:
      if (auto alloca = llvm::dyn_cast<llvm::AllocaInst>(sub))
        return irb.CreateLoad(alloca->getAllocatedType(), alloca);
      if (auto gv = llvm::dyn_cast<llvm::GlobalVariable>(sub))
        return irb.CreateLoad(gv->getValueType(), gv);
      return sub;
    case ImplicitCastExpr::kIntegralCast:
      return irb.CreateIntCast(sub, self(obj->type), true);
    case ImplicitCastExpr::kFunctionToPointerDecay:
      return sub;
    case ImplicitCastExpr::kArrayToPointerDecay:
      if (auto alloca = llvm::dyn_cast<llvm::AllocaInst>(sub))
        return irb.CreateInBoundsGEP(alloca->getAllocatedType(), alloca, {llvm::ConstantInt::get(llvm::Type::getInt32Ty(mCtx), 0), llvm::ConstantInt::get(llvm::Type::getInt32Ty(mCtx), 0)});
      if (auto gv = llvm::dyn_cast<llvm::GlobalVariable>(sub))
        return irb.CreateInBoundsGEP(gv->getValueType(), gv, {llvm::ConstantInt::get(llvm::Type::getInt32Ty(mCtx), 0), llvm::ConstantInt::get(llvm::Type::getInt32Ty(mCtx), 0)});
      ABORT();
    case ImplicitCastExpr::kNoOp:
      return sub;
    default:
      ABORT();
  }
}

llvm::Value*
EmitIR::operator()(InitListExpr* obj)
{
  // This is handled specially in VarDecl
  ABORT();
}

