// Stack to track break/continue destinations
std::vector<llvm::BasicBlock*> mBreakTargets;
std::vector<llvm::BasicBlock*> mContinueTargets;

void
EmitIR::operator()(Stmt* obj)
{
  if (auto p = obj->dcst<CompoundStmt>())
    return self(p);
  if (auto p = obj->dcst<ReturnStmt>())
    return self(p);
  if (auto p = obj->dcst<DeclStmt>())
    return self(p);
  if (auto p = obj->dcst<ExprStmt>())
    return self(p);
  if (auto p = obj->dcst<IfStmt>())
    return self(p);
  if (auto p = obj->dcst<WhileStmt>())
    return self(p);
  if (auto p = obj->dcst<BreakStmt>())
    return self(p);
  if (auto p = obj->dcst<ContinueStmt>())
    return self(p);
  if (auto p = obj->dcst<NullStmt>())
    return; // nothing to do
  ABORT();
}

void
EmitIR::operator()(CompoundStmt* obj)
{
  for (auto&& stmt : obj->subs)
    self(stmt);
}

void
EmitIR::operator()(ReturnStmt* obj)
{
  auto& irb = *mCurIrb;
  if (!obj->expr) {
    irb.CreateRetVoid();
  } else {
    auto retVal = self(obj->expr);
    irb.CreateRet(retVal);
  }
  // Create an unreachable block after return
  auto exitBb = llvm::BasicBlock::Create(mCtx, "return_exit", mCurFunc);
  irb.SetInsertPoint(exitBb);
}

void
EmitIR::operator()(DeclStmt* obj)
{
  for (auto&& decl : obj->decls)
    self(decl);
}

void
EmitIR::operator()(ExprStmt* obj)
{
  if (obj->expr)
    self(obj->expr);
}

void
EmitIR::operator()(IfStmt* obj)
{
  auto& irb = *mCurIrb;
  auto cond = self(obj->cond);
  auto condBool = irb.CreateICmpNE(cond, llvm::ConstantInt::get(cond->getType(), 0));

  auto thenBb = llvm::BasicBlock::Create(mCtx, "if.then", mCurFunc);
  auto elseBb = llvm::BasicBlock::Create(mCtx, "if.else", mCurFunc);
  auto mergeBb = llvm::BasicBlock::Create(mCtx, "if.merge", mCurFunc);

  irb.CreateCondBr(condBool, thenBb, elseBb);

  irb.SetInsertPoint(thenBb);
  self(obj->then);
  if (!thenBb->getTerminator())
    irb.CreateBr(mergeBb);

  irb.SetInsertPoint(elseBb);
  if (obj->else_)
    self(obj->else_);
  if (!elseBb->getTerminator())
    irb.CreateBr(mergeBb);

  irb.SetInsertPoint(mergeBb);
}

void
EmitIR::operator()(WhileStmt* obj)
{
  auto& irb = *mCurIrb;

  auto condBb = llvm::BasicBlock::Create(mCtx, "while.cond", mCurFunc);
  auto bodyBb = llvm::BasicBlock::Create(mCtx, "while.body", mCurFunc);
  auto exitBb = llvm::BasicBlock::Create(mCtx, "while.exit", mCurFunc);

  mBreakTargets.push_back(exitBb);
  mContinueTargets.push_back(condBb);

  irb.CreateBr(condBb);

  irb.SetInsertPoint(condBb);
  auto cond = self(obj->cond);
  auto condBool = irb.CreateICmpNE(cond, llvm::ConstantInt::get(cond->getType(), 0));
  irb.CreateCondBr(condBool, bodyBb, exitBb);

  irb.SetInsertPoint(bodyBb);
  self(obj->body);
  if (!bodyBb->getTerminator())
    irb.CreateBr(condBb);

  mBreakTargets.pop_back();
  mContinueTargets.pop_back();

  irb.SetInsertPoint(exitBb);
}

void
EmitIR::operator()(BreakStmt* obj)
{
  auto& irb = *mCurIrb;
  if (mBreakTargets.empty())
    ABORT();
  irb.CreateBr(mBreakTargets.back());
  // Create unreachable block
  auto exitBb = llvm::BasicBlock::Create(mCtx, "break.exit", mCurFunc);
  irb.SetInsertPoint(exitBb);
}

void
EmitIR::operator()(ContinueStmt* obj)
{
  auto& irb = *mCurIrb;
  if (mContinueTargets.empty())
    ABORT();
  irb.CreateBr(mContinueTargets.back());
  // Create unreachable block
  auto exitBb = llvm::BasicBlock::Create(mCtx, "continue.exit", mCurFunc);
  irb.SetInsertPoint(exitBb);
}

