#include "EmitIR.hpp"
#include "llvm/Transforms/Utils/ModuleUtils.h"

#define self (*this)

using namespace asg;

EmitIR::EmitIR(Obj::Mgr& mgr, llvm::LLVMContext& ctx, llvm::StringRef mid)
  : mMgr(mgr)
  , mMod(mid, ctx)
  , mCtx(ctx)
  , mIntTy(llvm::Type::getInt32Ty(ctx))
  , mCurIrb(std::make_unique<llvm::IRBuilder<>>(ctx))
  , mCtorTy(llvm::FunctionType::get(llvm::Type::getVoidTy(ctx), false))
{
}

llvm::Module&
EmitIR::operator()(asg::TranslationUnit* tu)
{
  for (auto&& i : tu->decls)
    self(i);
  return mMod;
}

//==============================================================================
// 类型
//==============================================================================

llvm::Type*
EmitIR::operator()(const Type* type)
{
  if (type->texp == nullptr) {
    switch (type->spec) {
      case Type::Spec::kVoid:
        return llvm::Type::getVoidTy(mCtx);
      case Type::Spec::kInt:
        return llvm::Type::getInt32Ty(mCtx);
      case Type::Spec::kChar:
        return llvm::Type::getInt8Ty(mCtx);
      case Type::Spec::kLong:
        return llvm::Type::getInt64Ty(mCtx);
      case Type::Spec::kLongLong:
        return llvm::Type::getInt64Ty(mCtx);
      default:
        ABORT();
    }
  }

  Type subt;
  subt.spec = type->spec;
  subt.qual = type->qual;
  subt.texp = type->texp->sub;

  if (auto p = type->texp->dcst<PointerType>()) {
    return llvm::PointerType::get(mCtx, 0);
  }

  if (auto p = type->texp->dcst<ArrayType>()) {
    auto elemTy = self(&subt);
    if (p->len == ArrayType::kUnLen)
      ABORT();
    return llvm::ArrayType::get(elemTy, p->len);
  }

  if (auto p = type->texp->dcst<FunctionType>()) {
    std::vector<llvm::Type*> pty;
    for (auto& param : p->params)
      pty.push_back(self(param));
    return llvm::FunctionType::get(self(&subt), std::move(pty), false);
  }

  ABORT();
}

//==============================================================================
// 表达式
//==============================================================================

llvm::Value*
EmitIR::operator()(Expr* obj)
{
  if (auto p = obj->dcst<IntegerLiteral>())
    return self(p);
  if (auto p = obj->dcst<DeclRefExpr>())
    return self(p);
  if (auto p = obj->dcst<BinaryExpr>())
    return self(p);
  if (auto p = obj->dcst<UnaryExpr>())
    return self(p);
  if (auto p = obj->dcst<CallExpr>())
    return self(p);
  if (auto p = obj->dcst<ParenExpr>())
    return self(p);
  if (auto p = obj->dcst<ImplicitCastExpr>())
    return self(p);
  if (auto p = obj->dcst<InitListExpr>())
    return self(p);
  if (auto p = obj->dcst<ArraySubscriptExpr>())
    return self(p);
  ABORT();
}

llvm::Constant*
EmitIR::operator()(IntegerLiteral* obj)
{
  return llvm::ConstantInt::get(self(obj->type), obj->val);
}

llvm::Value*
EmitIR::operator()(DeclRefExpr* obj)
{
  auto decl = obj->decl;
  if (auto gv = llvm::dyn_cast<llvm::GlobalVariable>(decl->any))
    return gv;
  if (auto func = llvm::dyn_cast<llvm::Function>(decl->any))
    return func;
  if (auto alloca = llvm::dyn_cast<llvm::AllocaInst>(decl->any))
    return alloca;
  ABORT();
}

llvm::Value*
EmitIR::operator()(BinaryExpr* obj)
{
  auto& irb = *mCurIrb;

  // Assignment
  if (obj->op == BinaryExpr::kAssign) {
    auto lhs = self(obj->lft);
    auto rhs = self(obj->rht);
    if (auto alloca = llvm::dyn_cast<llvm::AllocaInst>(lhs))
      irb.CreateStore(rhs, alloca);
    else if (auto gv = llvm::dyn_cast<llvm::GlobalVariable>(lhs))
      irb.CreateStore(rhs, gv);
    else
      ABORT();
    return rhs;
  }

  // Comma
  if (obj->op == BinaryExpr::kComma) {
    self(obj->lft);
    return self(obj->rht);
  }

  // Index (array subscript)
  if (obj->op == BinaryExpr::kIndex) {
    auto arr = self(obj->lft);
    auto idx = self(obj->rht);
    llvm::Value* elemPtr;
    if (auto alloca = llvm::dyn_cast<llvm::AllocaInst>(arr)) {
      elemPtr = irb.CreateInBoundsGEP(alloca->getAllocatedType(), alloca, {llvm::ConstantInt::get(llvm::Type::getInt32Ty(mCtx), 0), idx});
    } else if (auto gv = llvm::dyn_cast<llvm::GlobalVariable>(arr)) {
      elemPtr = irb.CreateInBoundsGEP(gv->getValueType(), gv, {llvm::ConstantInt::get(llvm::Type::getInt32Ty(mCtx), 0), idx});
    } else {
      // Pointer type - treat as pointer arithmetic
      elemPtr = irb.CreateInBoundsGEP(mIntTy, arr, idx);
    }
    return irb.CreateLoad(mIntTy, elemPtr);
  }

  auto lhs = self(obj->lft);
  auto rhs = self(obj->rht);

  switch (obj->op) {
    case BinaryExpr::kAdd:
      return irb.CreateAdd(lhs, rhs);
    case BinaryExpr::kSub:
      return irb.CreateSub(lhs, rhs);
    case BinaryExpr::kMul:
      return irb.CreateMul(lhs, rhs);
    case BinaryExpr::kDiv:
      return irb.CreateSDiv(lhs, rhs);
    case BinaryExpr::kMod:
      return irb.CreateSRem(lhs, rhs);
    case BinaryExpr::kGt:
      return irb.CreateICmpSGT(lhs, rhs);
    case BinaryExpr::kLt:
      return irb.CreateICmpSLT(lhs, rhs);
    case BinaryExpr::kGe:
      return irb.CreateICmpSGE(lhs, rhs);
    case BinaryExpr::kLe:
      return irb.CreateICmpSLE(lhs, rhs);
    case BinaryExpr::kEq:
      return irb.CreateICmpEQ(lhs, rhs);
    case BinaryExpr::kNe:
      return irb.CreateICmpNE(lhs, rhs);
    case BinaryExpr::kAnd: {
      // Short-circuit: lhs && rhs
      auto lhsBb = irb.GetInsertBlock();
      auto rhsBb = llvm::BasicBlock::Create(mCtx, "and.rhs", mCurFunc);
      auto mergeBb = llvm::BasicBlock::Create(mCtx, "and.merge", mCurFunc);
      auto lhsBool = irb.CreateICmpNE(lhs, llvm::ConstantInt::get(lhs->getType(), 0));
      irb.CreateCondBr(lhsBool, rhsBb, mergeBb);
      irb.SetInsertPoint(rhsBb);
      auto rhsVal = self(obj->rht);
      auto rhsBool = irb.CreateICmpNE(rhsVal, llvm::ConstantInt::get(rhsVal->getType(), 0));
      auto rhsResult = irb.CreateZExt(rhsBool, mIntTy);
      irb.CreateBr(mergeBb);
      irb.SetInsertPoint(mergeBb);
      auto phi = irb.CreatePHI(mIntTy, 2);
      phi->addIncoming(llvm::ConstantInt::get(mIntTy, 0), lhsBb);
      phi->addIncoming(rhsResult, rhsBb);
      return phi;
    }
    case BinaryExpr::kOr: {
      // Short-circuit: lhs || rhs
      auto lhsBb = irb.GetInsertBlock();
      auto rhsBb = llvm::BasicBlock::Create(mCtx, "or.rhs", mCurFunc);
      auto mergeBb = llvm::BasicBlock::Create(mCtx, "or.merge", mCurFunc);
      auto lhsBool = irb.CreateICmpNE(lhs, llvm::ConstantInt::get(lhs->getType(), 0));
      irb.CreateCondBr(lhsBool, mergeBb, rhsBb);
      irb.SetInsertPoint(rhsBb);
      auto rhsVal = self(obj->rht);
      auto rhsBool = irb.CreateICmpNE(rhsVal, llvm::ConstantInt::get(rhsVal->getType(), 0));
      auto rhsResult = irb.CreateZExt(rhsBool, mIntTy);
      irb.CreateBr(mergeBb);
      irb.SetInsertPoint(mergeBb);
      auto phi = irb.CreatePHI(mIntTy, 2);
      phi->addIncoming(llvm::ConstantInt::get(mIntTy, 1), lhsBb);
      phi->addIncoming(rhsResult, rhsBb);
      return phi;
    }
    default:
      ABORT();
  }
}

llvm::Value*
EmitIR::operator()(UnaryExpr* obj)
{
  auto& irb = *mCurIrb;
  auto sub = self(obj->sub);
  switch (obj->op) {
    case UnaryExpr::kPos:
      return sub;
    case UnaryExpr::kNeg:
      return irb.CreateNeg(sub);
    case UnaryExpr::kNot:
      return irb.CreateXor(sub, llvm::ConstantInt::get(sub->getType(), 1));
    default:
      ABORT();
  }
}

llvm::Value*
EmitIR::operator()(CallExpr* obj)
{
  auto& irb = *mCurIrb;
  auto callee = self(obj->head);
  auto func = llvm::dyn_cast<llvm::Function>(callee);
  if (!func)
    ABORT();

  std::vector<llvm::Value*> args;
  for (auto&& arg : obj->args)
    args.push_back(self(arg));
  return irb.CreateCall(func, args);
}

llvm::Value*
EmitIR::operator()(ParenExpr* obj)
{
  return self(obj->sub);
}

llvm::Value*
EmitIR::operator()(ImplicitCastExpr* obj)
{
  auto sub = self(obj->sub);
  auto& irb = *mCurIrb;
  switch (obj->kind) {
    case ImplicitCastExpr::kLValueToRValue:
      if (auto alloca = llvm::dyn_cast<llvm::AllocaInst>(sub))
        return irb.CreateLoad(alloca->getAllocatedType(), alloca);
      if (auto gv = llvm::dyn_cast<llvm::GlobalVariable>(sub))
        return irb.CreateLoad(gv->getValueType(), gv);
      return sub;
    case ImplicitCastExpr::kIntegralCast:
      return irb.CreateIntCast(sub, self(obj->type), true);
    case ImplicitCastExpr::kFunctionToPointerDecay:
      return sub;
    case ImplicitCastExpr::kArrayToPointerDecay:
      if (auto alloca = llvm::dyn_cast<llvm::AllocaInst>(sub))
        return irb.CreateInBoundsGEP(alloca->getAllocatedType(), alloca, {llvm::ConstantInt::get(llvm::Type::getInt32Ty(mCtx), 0), llvm::ConstantInt::get(llvm::Type::getInt32Ty(mCtx), 0)});
      if (auto gv = llvm::dyn_cast<llvm::GlobalVariable>(sub))
        return irb.CreateInBoundsGEP(gv->getValueType(), gv, {llvm::ConstantInt::get(llvm::Type::getInt32Ty(mCtx), 0), llvm::ConstantInt::get(llvm::Type::getInt32Ty(mCtx), 0)});
      ABORT();
    case ImplicitCastExpr::kNoOp:
      return sub;
    default:
      ABORT();
  }
}

llvm::Value*
EmitIR::operator()(InitListExpr* obj)
{
  // This is handled specially in VarDecl
  ABORT();
}

//==============================================================================
// 语句
//==============================================================================

// Stack to track break/continue destinations
std::vector<llvm::BasicBlock*> mBreakTargets;
std::vector<llvm::BasicBlock*> mContinueTargets;

void
EmitIR::operator()(Stmt* obj)
{
  if (auto p = obj->dcst<CompoundStmt>())
    return self(p);
  if (auto p = obj->dcst<ReturnStmt>())
    return self(p);
  if (auto p = obj->dcst<DeclStmt>())
    return self(p);
  if (auto p = obj->dcst<ExprStmt>())
    return self(p);
  if (auto p = obj->dcst<IfStmt>())
    return self(p);
  if (auto p = obj->dcst<WhileStmt>())
    return self(p);
  if (auto p = obj->dcst<BreakStmt>())
    return self(p);
  if (auto p = obj->dcst<ContinueStmt>())
    return self(p);
  if (auto p = obj->dcst<NullStmt>())
    return; // nothing to do
  ABORT();
}

void
EmitIR::operator()(CompoundStmt* obj)
{
  for (auto&& stmt : obj->subs)
    self(stmt);
}

void
EmitIR::operator()(ReturnStmt* obj)
{
  auto& irb = *mCurIrb;
  if (!obj->expr) {
    irb.CreateRetVoid();
  } else {
    auto retVal = self(obj->expr);
    irb.CreateRet(retVal);
  }
  // Create an unreachable block after return
  auto exitBb = llvm::BasicBlock::Create(mCtx, "return_exit", mCurFunc);
  irb.SetInsertPoint(exitBb);
}

void
EmitIR::operator()(DeclStmt* obj)
{
  for (auto&& decl : obj->decls)
    self(decl);
}

void
EmitIR::operator()(ExprStmt* obj)
{
  if (obj->expr)
    self(obj->expr);
}

void
EmitIR::operator()(IfStmt* obj)
{
  auto& irb = *mCurIrb;
  auto cond = self(obj->cond);
  auto condBool = irb.CreateICmpNE(cond, llvm::ConstantInt::get(cond->getType(), 0));

  auto thenBb = llvm::BasicBlock::Create(mCtx, "if.then", mCurFunc);
  auto elseBb = llvm::BasicBlock::Create(mCtx, "if.else", mCurFunc);
  auto mergeBb = llvm::BasicBlock::Create(mCtx, "if.merge", mCurFunc);

  irb.CreateCondBr(condBool, thenBb, elseBb);

  irb.SetInsertPoint(thenBb);
  self(obj->then);
  if (!thenBb->getTerminator())
    irb.CreateBr(mergeBb);

  irb.SetInsertPoint(elseBb);
  if (obj->else_)
    self(obj->else_);
  if (!elseBb->getTerminator())
    irb.CreateBr(mergeBb);

  irb.SetInsertPoint(mergeBb);
}

void
EmitIR::operator()(WhileStmt* obj)
{
  auto& irb = *mCurIrb;

  auto condBb = llvm::BasicBlock::Create(mCtx, "while.cond", mCurFunc);
  auto bodyBb = llvm::BasicBlock::Create(mCtx, "while.body", mCurFunc);
  auto exitBb = llvm::BasicBlock::Create(mCtx, "while.exit", mCurFunc);

  mBreakTargets.push_back(exitBb);
  mContinueTargets.push_back(condBb);

  irb.CreateBr(condBb);

  irb.SetInsertPoint(condBb);
  auto cond = self(obj->cond);
  auto condBool = irb.CreateICmpNE(cond, llvm::ConstantInt::get(cond->getType(), 0));
  irb.CreateCondBr(condBool, bodyBb, exitBb);

  irb.SetInsertPoint(bodyBb);
  self(obj->body);
  if (!bodyBb->getTerminator())
    irb.CreateBr(condBb);

  mBreakTargets.pop_back();
  mContinueTargets.pop_back();

  irb.SetInsertPoint(exitBb);
}

void
EmitIR::operator()(BreakStmt* obj)
{
  auto& irb = *mCurIrb;
  if (mBreakTargets.empty())
    ABORT();
  irb.CreateBr(mBreakTargets.back());
  // Create unreachable block
  auto exitBb = llvm::BasicBlock::Create(mCtx, "break.exit", mCurFunc);
  irb.SetInsertPoint(exitBb);
}

void
EmitIR::operator()(ContinueStmt* obj)
{
  auto& irb = *mCurIrb;
  if (mContinueTargets.empty())
    ABORT();
  irb.CreateBr(mContinueTargets.back());
  // Create unreachable block
  auto exitBb = llvm::BasicBlock::Create(mCtx, "continue.exit", mCurFunc);
  irb.SetInsertPoint(exitBb);
}

//==============================================================================
// 声明
//==============================================================================

void
EmitIR::operator()(Decl* obj)
{
  if (auto p = obj->dcst<VarDecl>())
    return self(p);
  if (auto p = obj->dcst<FunctionDecl>())
    return self(p);
  ABORT();
}

void
EmitIR::operator()(VarDecl* obj)
{
  auto ty = self(obj->type);

  // Check if this is a global variable
  if (mCurFunc == nullptr) {
    // Global variable
    llvm::Constant* initVal = nullptr;
    if (obj->init) {
      if (auto p = obj->init->dcst<IntegerLiteral>())
        initVal = self(p);
      else if (auto p = obj->init->dcst<InitListExpr>()) {
        // Handle init list for arrays
        std::vector<llvm::Constant*> elems;
        for (auto&& e : p->list) {
          if (auto il = e->dcst<IntegerLiteral>())
            elems.push_back(self(il));
          else
            ABORT();
        }
        initVal = llvm::ConstantArray::get(llvm::dyn_cast<llvm::ArrayType>(ty), elems);
      }
    }
    if (!initVal) {
      // Default initializer
      if (ty->isIntOrIntVectorTy())
        initVal = llvm::ConstantInt::get(ty, 0);
      else if (auto arrTy = llvm::dyn_cast<llvm::ArrayType>(ty))
        initVal = llvm::ConstantAggregateZero::get(arrTy);
      else
        initVal = llvm::ConstantPointerNull::get(llvm::PointerType::get(mCtx, 0));
    }
    auto gv = new llvm::GlobalVariable(mMod, ty, false, llvm::GlobalVariable::ExternalLinkage, initVal, obj->name);
    obj->any = gv;
    return;
  }

  // Local variable - alloca
  auto& irb = *mCurIrb;
  auto alloca = irb.CreateAlloca(ty, nullptr, obj->name);
  obj->any = alloca;

  // Initialize
  if (obj->init) {
    if (auto p = obj->init->dcst<IntegerLiteral>()) {
      irb.CreateStore(self(p), alloca);
    } else if (auto p = obj->init->dcst<InitListExpr>()) {
      // Handle init list for arrays
      auto arrTy = llvm::dyn_cast<llvm::ArrayType>(ty);
      if (!arrTy) ABORT();
      for (unsigned i = 0; i < p->list.size(); ++i) {
        auto elemPtr = irb.CreateInBoundsGEP(arrTy, alloca, {llvm::ConstantInt::get(llvm::Type::getInt32Ty(mCtx), 0), llvm::ConstantInt::get(llvm::Type::getInt32Ty(mCtx), i)});
        if (auto il = p->list[i]->dcst<IntegerLiteral>())
          irb.CreateStore(self(il), elemPtr);
        else
          ABORT();
      }
    } else {
      auto val = self(obj->init);
      irb.CreateStore(val, alloca);
    }
  } else {
    // Default initialize to 0
    if (ty->isIntOrIntVectorTy())
      irb.CreateStore(llvm::ConstantInt::get(ty, 0), alloca);
  }
}

void
EmitIR::operator()(FunctionDecl* obj)
{
  auto fty = llvm::dyn_cast<llvm::FunctionType>(self(obj->type));
  auto func = llvm::Function::Create(
    fty, llvm::GlobalVariable::ExternalLinkage, obj->name, mMod);

  obj->any = func;

  if (obj->body == nullptr)
    return;

  auto entryBb = llvm::BasicBlock::Create(mCtx, "entry", func);
  mCurIrb->SetInsertPoint(entryBb);

  // Handle function parameters
  unsigned idx = 0;
  for (auto& arg : func->args()) {
    if (idx < obj->params.size()) {
      auto paramDecl = obj->params[idx];
      auto alloca = mCurIrb->CreateAlloca(arg.getType(), nullptr, paramDecl->name);
      mCurIrb->CreateStore(&arg, alloca);
      paramDecl->any = alloca;
    }
    idx++;
  }

  mCurFunc = func;
  self(obj->body);

  // Add terminator if needed
  auto& exitIrb = *mCurIrb;
  if (!exitIrb.GetInsertBlock()->getTerminator()) {
    if (fty->getReturnType()->isVoidTy())
      exitIrb.CreateRetVoid();
    else
      exitIrb.CreateUnreachable();
  }
}
